function factorial(n, total = 1) {
  if (n <= 1) return total;
  return factorial(n - 1, n * total);
}

console.log(factorial(5)); // 120

function factorialSafe(n) {
  let total = 1;

  for (let i = 2; i <= n; i++) {
    total *= i;
  }

  return total;
}
